// src/pages/RegisterManageSub2Page.js (Tên file vẫn giữ nguyên theo bạn)
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

function FarmListPage() { // Tên component bạn nên đổi thành FarmListPage cho rõ ràng
  const [farms, setFarms] = useState([]);
  const [filter, setFilter] = useState('');
  const navigate = useNavigate();
  const token = localStorage.getItem('token'); // Lấy token để xác thực API

  useEffect(() => {
    // Đảm bảo API call có token để xác thực
    axios.get('http://localhost:10000/api/farms', {
      headers: {
        Authorization: `Bearer ${token}` // Thêm token vào header
      }
    })
      .then(res => setFarms(res.data))
      .catch(err => console.error('❌ Lỗi lấy danh sách:', err));
  }, [token]); // Thêm token vào dependency array

  const handleDelete = async (id) => {
    if (window.confirm('Bạn có chắc chắn muốn xoá?')) {
      try {
        await axios.delete(`http://localhost:10000/api/farms/${id}`, {
          headers: {
            Authorization: `Bearer ${token}`
          }
        });
        setFarms(farms.filter(f => f._id !== id));
        alert('Xoá thành công!'); // Thêm thông báo thành công
      } catch (error) {
        console.error('Lỗi khi xoá:', error);
        alert('Xoá thất bại');
      }
    }
  };

  const handleEdit = (id) => {
    // Thay đổi alert bằng điều hướng đến trang chỉnh sửa Farm
    navigate(`/edit-farm/${id}`);
  };

  const handleView = (id) => {
    navigate(`/farm-details/${id}`);
  };

  const filteredFarms = farms.filter(f =>
    (f.tinh || '').toLowerCase().includes(filter.toLowerCase()) ||
    (f.tenCoSo || '').toLowerCase().includes(filter.toLowerCase()) ||
    (f.chuTrai || '').toLowerCase().includes(filter.toLowerCase()) // Cho phép tìm kiếm theo chủ trại
  );

  return (
    <div style={{ padding: 20 }}>
      <h2>📋 Danh sách cơ sở nuôi</h2>

      <input
        type="text"
        placeholder="🔍 Tìm kiếm theo tỉnh, tên cơ sở, hoặc chủ trại..."
        value={filter}
        onChange={e => setFilter(e.target.value)}
        style={{ marginBottom: 12, padding: 8, width: '50%' }}
      />

      <table border="1" cellPadding="8" style={{ width: '100%', borderCollapse: 'collapse' }}>
        <thead style={{ background: '#f0f0f0' }}>
          <tr>
            <th>Tên cơ sở</th>
            <th>Tỉnh</th>
            <th>Huyện</th>
            <th>Xã</th>
            <th>Chủ trại</th>
            <th>SĐT</th>
            <th>🛠️</th>
          </tr>
        </thead>
        <tbody>
          {filteredFarms.map((f, i) => (
            <tr key={i}>
              <td>{f.tenCoSo}</td>
              <td>{f.tinh}</td>
              <td>{f.huyen}</td>
              <td>{f.xa}</td>
              <td>{f.chuTrai}</td> {/* Hiển thị Chủ trại */}
              <td>{f.soDienThoai}</td>
              <td>
                <button onClick={() => handleView(f._id)}>👁️</button>{' '}
                <button onClick={() => handleEdit(f._id)}>✏️</button>{' '} {/* Nút Edit */}
                <button onClick={() => handleDelete(f._id)}>🗑️</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default FarmListPage; // Export với tên mới
